import{_ as e,o as i,c as a,a2 as s}from"./chunks/framework.BtKjyiyt.js";const p=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":null}'),o={name:"configuration.md"};function n(l,t,r,d,h,g){return i(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><h2 id="Settings-" tabindex="-1">Settings (⚙) <a class="header-anchor" href="#Settings-" aria-label="Permalink to &quot;Settings (⚙) {#Settings-}&quot;">​</a></h2><p>Open the gear in the top bar (or ⌘K → Settings). Settings persist per-browser in localStorage.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Setting</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>Live-update debounce</strong></td><td style="text-align:right;">Minimum delay (ms) between live recomputes while dragging a control. Higher = fewer recomputes on a slow kernel.</td></tr><tr><td style="text-align:right;"><strong>Full page width</strong></td><td style="text-align:right;">Use the full window width instead of the centered column.</td></tr><tr><td style="text-align:right;"><strong>Theme</strong></td><td style="text-align:right;">Dark (default).</td></tr><tr><td style="text-align:right;"><strong>Editor syntax</strong></td><td style="text-align:right;">Syntax-highlighting palette for the editor — Dark+, Monokai, Dracula, or Nord.</td></tr><tr><td style="text-align:right;"><strong>Agent model</strong></td><td style="text-align:right;">Sonnet / Opus / Haiku, plus any locally-installed Ollama model.</td></tr><tr><td style="text-align:right;"><strong>Agent permissions</strong></td><td style="text-align:right;"><code>lab</code> / <code>auto</code> / <code>default</code> / <code>bypass</code> preset for the agent.</td></tr></tbody></table><p>Model and permission changes <a href="./agent">reap the agent</a> so the next message respawns on the new setting (the transcript is kept).</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/settings.png" alt="" style="width:520px;max-width:100%;"></p><h2 id="Notebook-config" tabindex="-1">Notebook config <a class="header-anchor" href="#Notebook-config" aria-label="Permalink to &quot;Notebook config {#Notebook-config}&quot;">​</a></h2><p>The <strong>⚙ Settings</strong> above are per-browser and apply to every notebook. <strong>Per-notebook</strong> overrides live in a separate panel — <strong>☰ → 🎚 Notebook config</strong>. Each setting starts from your global default and can be <strong>pinned to this notebook</strong>; the pinned ones travel <em>in the <code>.jl</code></em>, so the notebook reopens the same way anywhere.</p><p>Typical per-notebook overrides:</p><ul><li><p><strong>Worker threads</strong> (<code>&quot;&lt;compute&gt;,&lt;interactive&gt;&quot;</code>) and <strong>parallel</strong> cell execution.</p></li><li><p><strong>Slides</strong> — mark the notebook as a <a href="./slides">slide deck</a> and set its options.</p></li><li><p><strong>Agent model / permissions</strong> — override the global agent defaults for this notebook (permissions are remembered locally and never written to the file).</p></li><li><p><strong>Autorun</strong> — whether the notebook runs its cells on open.</p></li></ul><p>Where a value crosses into other UI: the notebook&#39;s <strong>run location</strong> is the toolbar &quot;Running on&quot; picker (whole-notebook placement, <a href="./remotes">Remotes</a>), and its <strong>regions</strong> are the <a href="/KaimonSlate.jl/previews/PR9/regions#using-a-region-in-a-notebook">Destinations</a> it enables — both are saved in the same config footer.</p><h2 id="serving" tabindex="-1">Serving <a class="header-anchor" href="#serving" aria-label="Permalink to &quot;Serving&quot;">​</a></h2><p>The <a href="./installation"><code>slate</code> app</a> is the normal way to run the hub:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slate</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # start (or attach to) the hub + status TUI</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> notebook.jl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # also open a notebook</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --own</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # force a standalone hub even if a Kaimon extension is registered</span></span></code></pre></div><p>The hub port is <code>KAIMONSLATE_PORT</code> (default 8765); set <code>KAIMONSLATE_NO_OPEN=1</code> to never open a browser.</p><p>To drive the hub from your own script instead, the programmatic API is still available:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonSlate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">serve_notebook</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(path; host </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;127.0.0.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, port </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8765</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># blocking</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">h </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KaimonSlate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">start_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(path; port </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8765</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)                     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># non-blocking → Hub</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonSlate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stop_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(h)</span></span></code></pre></div><p><code>start_hub</code> / <code>open_notebook!</code> / <code>close_notebook!</code> / <code>stop_hub</code> give finer control over a multi-notebook hub. See the <a href="./api">API Reference</a>.</p><h2 id="Kernel-selection" tabindex="-1">Kernel selection <a class="header-anchor" href="#Kernel-selection" aria-label="Permalink to &quot;Kernel selection {#Kernel-selection}&quot;">​</a></h2><p>A notebook uses a <strong>gate worker</strong> when it sits inside a Julia project and Kaimon&#39;s gate is available; otherwise it runs <strong>in-process</strong>. The gate worker gives you a clean namespace, a tailable log (🪵), <a href="./packages">package management</a>, and isolation. There&#39;s no setting for this — it&#39;s chosen from the notebook&#39;s location. Restart a worker any time with <strong>⟲ Restart worker</strong> (top bar), or rebuild the namespace with <strong>↻ Rebuild</strong>.</p><p>A worker can also run on <strong>another machine</strong> — a workstation, GPU box, or cloud VM — with the notebook behaving exactly as if local. Set hosts up on the front page&#39;s <strong>🖧 Remotes</strong> dialog and place a whole notebook with <strong>Run on</strong>, or route individual cells to a named <a href="./regions">region</a> (kept warm for instant startup). See <a href="./remotes">Remotes</a>.</p><h2 id="Remote-worker-timing" tabindex="-1">Remote worker timing <a class="header-anchor" href="#Remote-worker-timing" aria-label="Permalink to &quot;Remote worker timing {#Remote-worker-timing}&quot;">​</a></h2><p>The SSH/connect/tunnel/transfer timeouts used when a worker runs on <a href="./remotes">another machine</a> default to values tuned for a LAN. A slow-auth, high-latency, or cold (heavy-precompile) host can legitimately exceed them — a cold cloud VM&#39;s first spawn, say, outrunning the 120 s dial deadline. Rather than rebuild, override any of them per machine in a <code>&quot;remote&quot;</code> object in <code>slate.json</code> (in your config home — <code>$XDG_CONFIG_HOME/kaimonslate/</code>, changes apply on the next hub start):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;remote&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;dial_deadline_cold&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">300</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;ssh_connect_timeout&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;pkg_op_timeout&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1800</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Each key also has a <code>KAIMONSLATE_*</code> environment-variable equivalent (handy for a one-off run or a test); precedence is <strong><code>slate.json</code> → env var → built-in default</strong>. Values are <strong>seconds</strong> unless noted.</p><table tabindex="0"><thead><tr><th style="text-align:right;"><code>slate.json</code> key</th><th style="text-align:right;">Env var</th><th style="text-align:right;">Default</th><th style="text-align:right;">Governs</th></tr></thead><tbody><tr><td style="text-align:right;"><code>dial_deadline_cold</code></td><td style="text-align:right;"><code>KAIMONSLATE_DIAL_DEADLINE_COLD</code></td><td style="text-align:right;"><code>120</code></td><td style="text-align:right;">Cold-spawn dial — covers remote Julia boot + KaimonGate load.</td></tr><tr><td style="text-align:right;"><code>dial_deadline_probe</code></td><td style="text-align:right;"><code>KAIMONSLATE_DIAL_DEADLINE_PROBE</code></td><td style="text-align:right;"><code>15</code></td><td style="text-align:right;">Reattach-probe / warm-pool-adopt dial.</td></tr><tr><td style="text-align:right;"><code>dial_deadline_record</code></td><td style="text-align:right;"><code>KAIMONSLATE_DIAL_DEADLINE_RECORD</code></td><td style="text-align:right;"><code>5</code></td><td style="text-align:right;">Record-first dial (a live worker answers in well under a second).</td></tr><tr><td style="text-align:right;"><code>connect_deadline_local</code></td><td style="text-align:right;"><code>KAIMONSLATE_CONNECT_DEADLINE_LOCAL</code></td><td style="text-align:right;"><code>90</code></td><td style="text-align:right;">Local (<code>127.0.0.1</code>) worker connect deadline.</td></tr><tr><td style="text-align:right;"><code>ssh_connect_timeout</code></td><td style="text-align:right;"><code>KAIMONSLATE_SSH_CONNECT_TIMEOUT</code></td><td style="text-align:right;"><code>15</code></td><td style="text-align:right;"><code>ConnectTimeout</code> for every ssh/scp/rsync op.</td></tr><tr><td style="text-align:right;"><code>ssh_control_persist</code></td><td style="text-align:right;"><code>KAIMONSLATE_SSH_CONTROL_PERSIST</code></td><td style="text-align:right;"><code>120</code></td><td style="text-align:right;">SSH connection-mux master warm-hold past the last op.</td></tr><tr><td style="text-align:right;"><code>tunnel_alive_interval</code></td><td style="text-align:right;"><code>KAIMONSLATE_TUNNEL_ALIVE_INTERVAL</code></td><td style="text-align:right;"><code>5</code></td><td style="text-align:right;">Supervised tunnel <code>ServerAliveInterval</code>.</td></tr><tr><td style="text-align:right;"><code>tunnel_alive_count</code></td><td style="text-align:right;"><code>KAIMONSLATE_TUNNEL_ALIVE_COUNT</code></td><td style="text-align:right;"><code>3</code></td><td style="text-align:right;">Supervised tunnel <code>ServerAliveCountMax</code>.</td></tr><tr><td style="text-align:right;"><code>tunnel_respawn_backoff</code></td><td style="text-align:right;"><code>KAIMONSLATE_TUNNEL_RESPAWN_BACKOFF</code></td><td style="text-align:right;"><code>1</code></td><td style="text-align:right;">Backoff after a dropped forward before respawning it.</td></tr><tr><td style="text-align:right;"><code>probe_timeout</code></td><td style="text-align:right;"><code>KAIMONSLATE_PROBE_TIMEOUT</code></td><td style="text-align:right;"><code>4</code></td><td style="text-align:right;"><code>:direct</code> TCP port-open probe.</td></tr><tr><td style="text-align:right;"><code>firewall_giveup</code></td><td style="text-align:right;"><code>KAIMONSLATE_FIREWALL_GIVEUP</code></td><td style="text-align:right;"><code>10</code></td><td style="text-align:right;">Sustained SYN-drop ⇒ declare a firewall and fail fast.</td></tr><tr><td style="text-align:right;"><code>pkg_op_timeout</code></td><td style="text-align:right;"><code>KAIMONSLATE_PKG_OP_TIMEOUT</code></td><td style="text-align:right;"><code>900</code></td><td style="text-align:right;">Package add/rm/reconstruct — a heavy stack&#39;s resolve + precompile.</td></tr><tr><td style="text-align:right;"><code>sync_parent_timeout</code></td><td style="text-align:right;"><code>KAIMONSLATE_SYNC_PARENT_TIMEOUT</code></td><td style="text-align:right;"><code>600</code></td><td style="text-align:right;">Parent-project <code>/src</code> sync.</td></tr><tr><td style="text-align:right;"><code>blob_xfer_timeout</code></td><td style="text-align:right;"><code>KAIMONSLATE_BLOB_XFER_TIMEOUT</code></td><td style="text-align:right;"><code>600</code></td><td style="text-align:right;">Whole-binding / direct-blob boundary move.</td></tr><tr><td style="text-align:right;"><code>blob_chunk_timeout</code></td><td style="text-align:right;"><code>KAIMONSLATE_BLOB_CHUNK_TIMEOUT</code></td><td style="text-align:right;"><code>20</code></td><td style="text-align:right;">Per-chunk ZMQ recv/send timeout on a transfer.</td></tr><tr><td style="text-align:right;"><code>sysimage_lock_stale</code></td><td style="text-align:right;"><code>KAIMONSLATE_SYSIMAGE_LOCK_STALE</code></td><td style="text-align:right;"><code>1800</code></td><td style="text-align:right;">Concurrent sysimage-build lock staleness window.</td></tr><tr><td style="text-align:right;"><code>peer_bw_mbps</code></td><td style="text-align:right;"><code>KAIMONSLATE_PEER_BW_MBPS</code></td><td style="text-align:right;"><code>30</code></td><td style="text-align:right;">Assumed rate (MB/s) for an unmeasured worker→worker link.</td></tr></tbody></table><h2 id="Ollama-local-models" tabindex="-1">Ollama (local models) <a class="header-anchor" href="#Ollama-local-models" aria-label="Permalink to &quot;Ollama (local models) {#Ollama-local-models}&quot;">​</a></h2><p>The agent model dropdown lists models from your local Ollama install, queried from its HTTP API (embedding-only models are filtered out). Point at a non-default host with the standard environment variable:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OLLAMA_HOST</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:11434</span></span></code></pre></div><p>Driving a local model requires Kaimon&#39;s Ollama agent backend. Selecting a model stores it as <code>ollama:&lt;name&gt;</code>, which rides each chat turn.</p><h2 id="Environment-variables" tabindex="-1">Environment variables <a class="header-anchor" href="#Environment-variables" aria-label="Permalink to &quot;Environment variables {#Environment-variables}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Variable</th><th style="text-align:right;">Used for</th></tr></thead><tbody><tr><td style="text-align:right;"><code>KAIMONSLATE_PORT</code></td><td style="text-align:right;">Hub port for the <code>slate</code> app / server (default <code>8765</code>).</td></tr><tr><td style="text-align:right;"><code>KAIMONSLATE_NO_OPEN</code></td><td style="text-align:right;"><code>=1</code> → never open a browser when the <code>slate</code> app starts.</td></tr><tr><td style="text-align:right;"><code>OLLAMA_HOST</code></td><td style="text-align:right;">Ollama API endpoint for the model list (default <code>http://127.0.0.1:11434</code>).</td></tr><tr><td style="text-align:right;"><code>KAIMONSLATE_ASSET_BASE</code></td><td style="text-align:right;"><strong>Docs build only</strong> — points the site at the docs-assets GitHub Release for generated demo media. Unset locally → served from <code>public/assets/</code>.</td></tr></tbody></table>`,32)])])}const k=e(o,[["render",n]]);export{p as __pageData,k as default};
